#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n;
    cin>>n;
    long long a[n],b[n];
    for(int i=0;i<n;i++){
        cin>>a[i]>>b[i];
    }
    long long s=0;
    for(int i=0;i<n-1;i++){
        for(int j=n-2;j>=i;j--){
            if(a[j+1]>a[j]){
                long long t=a[j+1];
                a[j+1]=a[j];
                a[j]=t;
                t=b[j+1];
                b[j+1]=b[j];
                b[j]=t;
                s++;
            }
            else if(a[j+1]==a[j]&&b[j+1]>b[j]){
                long long t=a[j+1];
                a[j+1]=a[j];
                a[j]=t;
                t=b[j+1];
                b[j+1]=b[j];
                b[j]=t;
                s++;
            }
        }
    }
    cout<<s;
    return 0;
}
